const text = $json.output;

const nameMatch = text.match(/Product Name:\*\*\s*(.*)/);
const priceMatch = text.match(/Price:\*\*\s*Rs\.?([\d,\.]+)/);

let name = nameMatch ? nameMatch[1].trim() : null;
let price = priceMatch ? priceMatch[1].replace(/,/g, "") : null;

return [
  {
    json: {
      name: name,
      price: price ? Number(price) : null
    }
  }
];
